class Solution:
    def maxAbsoluteSum(self, nums):
        best = worst = 0
        cur_max = cur_min = 0
        for v in nums:
            cur_max = max(v, cur_max + v)
            cur_min = min(v, cur_min + v)
            best = max(best, cur_max)
            worst = min(worst, cur_min)
        return max(best, -worst)

