var maxAbsoluteSum = function(nums) {
    let best = 0, worst = 0, curMax = 0, curMin = 0;
    for (const v of nums) {
        curMax = Math.max(v, curMax + v);
        curMin = Math.min(v, curMin + v);
        best = Math.max(best, curMax);
        worst = Math.min(worst, curMin);
    }
    return Math.max(best, -worst);
};
